import com.google.gson.Gson;

public class TestGsonIssue {
  static class Base { public Base f; }
  static class Sub extends Base { public int i; Sub(int i) { this.i = i; } }
  public static void main(String[] args) {
    Base b = new Base();
    b.f = new Sub(2);
    String json = new Gson().toJson(b);
    System.out.println(json);
    if (!"{\"f\":{\"i\":2}}".equals(json)) throw new AssertionError(json);
  }
}
